int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int h, w, d;
    cin >> h >> w >> d;
    vector<string> s(h);
    vector<pair<int,int>> floor_cells;
    for (int i = 0; i < h; ++i) {
        cin >> s[i];
        for (int j = 0; j < w; ++j) if (s[i][j] == '.') floor_cells.push_back({i, j});
    }
    int f = floor_cells.size(), ans = 0;
    for (int i = 0; i < f; ++i) for (int j = i + 1; j < f; ++j) {
        int cnt = 0;
        for (auto [r, c] : floor_cells) {
            auto [r1, c1] = floor_cells[i];
            auto [r2, c2] = floor_cells[j];
            if (abs(r - r1) + abs(c - c1) <= d || abs(r - r2) + abs(c - c2) <= d) ++cnt;
        }
        ans = max(ans, cnt);
    }
    cout << ans << '\n';
    return 0;
}

