// 参考解：按题意实现核心算法。
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int h, w, d;
    cin >> h >> w >> d;
    vector<string> s(h);
    queue<pair<int,int>> q;
    vector<vector<int>> dist(h, vector<int>(w, -1));
    for (int i = 0; i < h; ++i) {
        cin >> s[i];
        for (int j = 0; j < w; ++j) if (s[i][j] == 'H') {
            dist[i][j] = 0;
            q.push({i, j});
        }
    }
    int dr[4] = {1, -1, 0, 0};
    int dc[4] = {0, 0, 1, -1};
    while (!q.empty()) {
        auto [r, c] = q.front(); q.pop();
        if (dist[r][c] == d) continue;
        for (int dir = 0; dir < 4; ++dir) {
            int nr = r + dr[dir], nc = c + dc[dir];
            if (nr < 0 || nr >= h || nc < 0 || nc >= w || s[nr][nc] == '#') continue;
            if (dist[nr][nc] == -1) {
                dist[nr][nc] = dist[r][c] + 1;
                q.push({nr, nc});
            }
        }
    }
    int ans = 0;
    for (int i = 0; i < h; ++i) for (int j = 0; j < w; ++j) ans += (dist[i][j] != -1);
    cout << ans << '\n';
    return 0;
}

