// 参考解：按题意实现核心算法。
bool ok(const string &s, const string &t, int k) {
    if (abs((int)s.size() - (int)t.size()) > k) return false;
    int i = 0, j = 0, diff = 0;
    while (i < (int)s.size() && j < (int)t.size()) {
        if (s[i] == t[j]) { ++i; ++j; }
        else {
            ++diff;
            if (diff > k) return false;
            if (s.size() == t.size()) { ++i; ++j; }
            else if (s.size() < t.size()) ++j;
            else ++i;
        }
    }
    diff += ((int)s.size() - i) + ((int)t.size() - j);
    return diff <= k;
}

