    int n, m;
    cin >> n >> m;
    vector<long long> b(n), w(m);
    for (auto &x : b) cin >> x;
    for (auto &x : w) cin >> x;
    sort(b.rbegin(), b.rend());
    sort(w.rbegin(), w.rend());
    vector<long long> pref_b(n + 1, 0), pref_w(m + 1, 0), best_w(m + 1, 0);
    for (int i = 0; i < n; ++i) pref_b[i + 1] = pref_b[i] + b[i];
    for (int i = 0; i < m; ++i) pref_w[i + 1] = pref_w[i] + w[i];
    for (int i = 1; i <= m; ++i) best_w[i] = max(best_w[i - 1], pref_w[i]);
    long long ans = 0;
    for (int blacks = 0; blacks <= n; ++blacks) {
        ans = max(ans, pref_b[blacks] + best_w[min(blacks, m)]);
    }
    cout << ans << '\n';
    return 0;
}
